import { Injectable, inject } from '@angular/core';
import { PermissionService } from '../../../core/services/permission.service';
import { PermissionExpression } from '../../../core/models/permission.model';

/**
 * Centralized service for evaluating client-scoped permissions.
 */
@Injectable({
  providedIn: 'root',
})
export class ClientPermissionsService {
  private readonly permissionService = inject(PermissionService);

  /**
   * Check if user has access to a specific permission expression in client scope.
   * Used by guards and tab filtering.
   */
  canAccessFeature(permissions: PermissionExpression | undefined): boolean {
    if (permissions === null || permissions === undefined) {
      return true; // No permission requirement means access allowed
    }

    return this.permissionService.canAccess(permissions, 'client');
  }
}
