import { CanActivateFn, Router } from '@angular/router';
import { inject } from '@angular/core';
import { ClientPermissionsService } from '../services/client-permissions.service';
import {
  CLIENT_ADMIN_FEATURES,
  ClientFeatureId,
} from '../components/clients/client-administration.config';
import { isNullOrUndefined } from '../../../shared/utils';

/**
 * Smart redirect guard that finds the first accessible child based on permissions.
 * Used for parent routes with children to avoid locking users out.
 *
 * @param parentPath - Parent route path segment
 * @param childIds - Array of child feature IDs to check, in order of preference
 * @returns Guard function that navigates to first accessible child or returns false
 */
export function createSmartRedirectGuard(
  parentPath: string,
  childIds: ClientFeatureId[],
): CanActivateFn {
  return (_route, state) => {
    const clientPermissionsService = inject(ClientPermissionsService);
    const router = inject(Router);

    // Get the clientId from the current URL
    const parts = state.url.split('/');
    const clientIdIndex = parts.indexOf('client');
    const clientId =
      clientIdIndex !== -1 && clientIdIndex + 1 < parts.length
        ? parts[clientIdIndex + 1]
        : null;

    if (isNullOrUndefined(clientId)) {
      return false;
    }

    // Find the first accessible child
    for (const childId of childIds) {
      const config = CLIENT_ADMIN_FEATURES[childId];
      const hasAccess = clientPermissionsService.canAccessFeature(
        'permissions' in config ? config.permissions : undefined,
      );

      if (hasAccess) {
        // Navigate to the first accessible child
        return router.createUrlTree([
          'admin',
          'client',
          clientId,
          parentPath,
          childId,
        ]);
      }
    }

    // If no children are accessible, redirect to unauthorized
    return false;
  };
}
